// Dữ liệu từ webhook
const webhook = $('Webhook Chat').first().json.body;
const query = webhook.query || '';
const topic = webhook.topic || '';
const history = webhook.history || '';
const imageData = webhook.imageData || null;
const imageMime = webhook.imageMime || null;
const fileText = webhook.fileText || null;
const fileName = webhook.fileName || null;

// KB data fetched from GitHub
let kbChunks = [];
try {
  const fetched = $('Fetch KB từ GitHub').first().json;
  kbChunks = Array.isArray(fetched) ? fetched : [];
} catch(e) { kbChunks = []; }

// Search relevant chunks
const searchTerms = query.toLowerCase().split(/\s+/).filter(t => t.length > 1);
const scored = kbChunks.map(chunk => {
  let score = 0;
  const cl = chunk.content.toLowerCase();
  searchTerms.forEach(term => { if (cl.includes(term)) score += 10; });
  if (chunk.keywords) chunk.keywords.forEach(kw => { if (query.toLowerCase().includes(kw.toLowerCase())) score += 20; });
  // Boost chunks có số liệu
  if (/\d+%|\d[\d,.]+\s*(VNĐ|đồng|ngày|tháng|lần|mm)/i.test(chunk.content) && score > 0) score += 25;
  if (/ĐIỀU\s+\d+/i.test(chunk.content) && score > 0) score += 15;
  return { ...chunk, score };
}).filter(c => c.score > 0).sort((a,b) => b.score - a.score).slice(0, 8);

// Build context (max 6000 chars)
let context = '';
let totalLen = 0;
for (const c of scored) {
  const entry = `[${c.source}, P${c.page}]: ${c.content}`;
  if (totalLen + entry.length > 6000) break;
  context += entry + '\n---\n';
  totalLen += entry.length;
}

// Thêm nội dung file khách gửi
if (fileText) {
  context = `[Tài liệu khách gửi: ${fileName}]:\n${fileText.slice(0,3000)}\n---\n` + context;
}

// System prompt
const hotline = '0902 982 029';
const systemPrompt = `Bạn là CHUYÊN GIA TƯ VẤN XÂY DỰNG, tư vấn trực tiếp cho CHỦ ĐẦU TƯ.\n\nCHỦ ĐỀ: ${topic}\n→ CHỈ trả lời trong phạm vi "${topic}". Ngoài chủ đề → nhắc chuyển.\n→ Ngoài lĩnh vực xây nhà → từ chối.\n\nNGUYÊN TẮC:\n1. Trả lời CỤ THỂ với số liệu (%, VNĐ, ngày). KHÔNG bịa. Dữ liệu ghi "…" → "do hai bên thỏa thuận".\n2. KHÔNG dẫn nguồn. KHÔNG nói "Theo Điều X". Trả lời như kiến thức của bạn.\n3. Đứng về phía chủ đầu tư. Cảnh báo rủi ro.\n4. Dùng Markdown (**bold**, - bullet). \n5. Xưng "em", gọi "anh/chị".\n6. KHÔNG gửi URL/link.\n7. Pháp lý, tranh chấp → khái quát + "Hotline: ${hotline}".\n8. Kết thúc bằng 1 câu hỏi dẫn dắt.`;

const userMessage = `TRI THỨC TÀI LIỆU:\n${context}\n\n${history ? 'LỊCH SỬ:\n' + history + '\n\n' : ''}CÂU HỎI: "${query}"`;

// Build Claude messages
const messages = [];
const userParts = [];

// Nếu có ảnh
if (imageData && imageMime) {
  userParts.push({
    type: 'image',
    source: { type: 'base64', media_type: imageMime, data: imageData }
  });
}
userParts.push({ type: 'text', text: userMessage });
messages.push({ role: 'user', content: userParts });

// Document links từ chunks
const docLinks = [...new Set(scored.map(c => c.source))].slice(0, 3);

return [{ json: { systemPrompt, messages, docLinks } }];

const claudeResponse = $('Claude AI').first().json;
const promptData = $('Search KB & Build Prompt').first().json;
let answer = '';

try {
  if (claudeResponse.content && claudeResponse.content[0]) {
    answer = claudeResponse.content[0].text;
  } else if (claudeResponse.error) {
    answer = 'Dạ, hệ thống đang bận. Anh/chị thử lại sau nhé.';
  }
} catch(e) {
  answer = 'Dạ, có lỗi xảy ra. Anh/chị thử hỏi lại nhé.';
}

return [{ json: { answer, docLinks: promptData.docLinks || [] } }];
